import { useEffect, useState } from "react";

export default function useGetSingleAPOD(apod) {
  const [image, setImage] = useState(null);

  let key = 'hK9L5EdqbSfX3VLvK84iefSH0yV3te6DYTv1JLG4';
  const url = `https://api.nasa.gov/planetary/apod?api_key=${key}`;

  useEffect(() => {    
    
    const getPhoto = async () => {
      const response = await fetch(url, {
        method: 'GET'
      })
      .then(response => response.json())
      .then(data => {
        setImage(data);
        console.log(data);
        localStorage.setItem('currentDay', data);
        const stuff = localStorage.getItem('currentDay');
        console.log(stuff);
      });
    };

    if (!apod) {
      getPhoto();
    }

    
  }, []);
  return image;
}
